使用可持久化平衡树处理区间复制。

使用倍增，建立表示复制 $2^1,2^2,2^3...$ 的节点，这些节点直接由两个子节点 merge 上来。复制 $k$ 次的话就是取对应的 $2^i$ 节点 merge 一下。

题目中的 2 操作也不难处理，直接处理 $2^i$ 节点与 $2^i$ 的反节点即可。

实现用了 leafy tree，因为 fhq 只能随机合并，合并复杂度为 $\log(siz_x+siz_y)$ 倍增处理会是 2log，而 leafy tree 合并复杂度为 $\log(\frac{siz_x}{siz_y})$ 倍增处理是 1log。

由于是模板题，直接放代码：

```cpp
#include<bits/stdc++.h>
#define For(i,a,b) for( int i=(a);i<=(b);++i)
#define Rep(i,a,b) for( int i=(a);i>=(b);--i)
using namespace std;
inline int read()
{
	char c=getchar();int x=0;bool f=0;
	for(;!isdigit(c);c=getchar())f^=!(c^45);
	for(;isdigit(c);c=getchar())x=(x<<1)+(x<<3)+(c^48);
	if(f)x=-x;return x;
}

#define fi first
#define se second
#define pb push_back
#define mkp make_pair
typedef pair<int,int>pii;
typedef vector<int>vi;

#define maxn 200005
#define inf 0x3f3f3f3f

int n,m;
char a[maxn];

#define N 50000005
int rt,sz[N],sum[N],ls[N],rs[N],rub[N],tot,top;
bool rev[N];

int newn(){
	if(top)return rub[top--];
	return ++tot;
} 

void up(int u){
	sz[u]=sz[ls[u]]+sz[rs[u]];
	sum[u]=sum[ls[u]]+sum[rs[u]];
}
int up(int l,int r){
	int u=newn();
	return ls[u]=l,rs[u]=r,up(u),u;
}
int copy(int p){
	int u=newn();
	ls[u]=ls[p],rs[u]=rs[p],sum[u]=sum[p],sz[u]=sz[p],rev[u]=rev[p];
	return u;
}
int newn(int x){
	int u=newn(); ls[u]=rs[u]=0;
	return sz[u]=1,sum[u]=x,u;
}
int build(int l,int r){
	if(l==r)return newn(a[l]&1);
	int m=l+r>>1; return up(build(l,m),build(m+1,r));
}
int pushr(int p){
	int u=copy(p);
	return rev[u]=rev[u]^1,swap(ls[u],rs[u]),u;
}
void down(int u){
	if(!rev[u]||!ls[u])return;
	ls[u]=pushr(ls[u]),rs[u]=pushr(rs[u]),rev[u]=0;
}

const double alp=1-sqrt(2)/2,delp=alp/(1-alp);
int merge(int u,int v){
	if(!u||!v)return u|v;
	if(sz[u]>=delp*sz[v]&&sz[v]>=delp*sz[u])return up(u,v);
	if(sz[u]<=sz[v]){
		down(v);
		int l=ls[v],r=rs[v];
		if(sz[r]>=alp*(sz[u]+sz[v]))return merge(merge(u,l),r);
		down(l);
		return merge(merge(u,ls[l]),merge(rs[l],r));
	}else{
		down(u);
		int l=ls[u],r=rs[u];
		if(sz[l]>=alp*(sz[u]+sz[v]))return merge(l,merge(r,v));
		down(r);
		return merge(merge(l,ls[r]),merge(rs[r],v)); 
	}
}
void split(int p,int k,int&x,int&y){
	if(!p||!k)return x=0,y=p,void();
	if(k==sz[p])return x=p,y=0,void();
	down(p);
	if(k<=sz[ls[p]])split(ls[p],k,x,y),y=merge(y,rs[p]);
	else split(rs[p],k-sz[ls[p]],x,y),x=merge(ls[p],x);
}
int bound(int p,int k){
	if(!ls[p])return 1;
	down(p);
	if(sum[ls[p]]>=k)return bound(ls[p],k);
	return sz[ls[p]]+bound(rs[p],k-sum[ls[p]]);
}

void del(int l,int r){
	int x,y,z,tmp;
	split(rt,r,tmp,z),split(tmp,l-1,x,y);
	rt=merge(x,z);
}
int ask(int k){
	if(sum[rt]<k)return -1;
	return bound(rt,k);
}

int op,p[33],q[33];
void work(int l,int r,int k,int o)
{
	int x,y,z,tmp,u=-1,i=0; op=o;
	split(rt,r,tmp,z),split(tmp,l-1,x,y);
	p[0]=y;
	if(!o){
		while((1<<(i+1))<=k)++i,p[i]=up(p[i-1],p[i-1]);
		For(j,0,i)if(k>>j&1)u=(u==-1?p[j]:merge(u,p[j]));
	}else{
		q[0]=pushr(p[0]); 
		while((1<<(i+1))<=k)++i,p[i]=up(p[i-1],q[i-1]),q[i]=up(q[i-1],p[i-1]);
		bool r=0;
		Rep(j,i,0)if(k>>j&1)tmp=(r?q[j]:p[j]),u=(u==-1?tmp:merge(u,tmp)),r^=1;
	}
	rt=merge(merge(x,u),z);
}

signed main()
{
	n=read();
	scanf("%s",a+1);
	rt=build(1,n);

	m=read();
	For(i,1,m){
		int o=read(),l,r,x,y,z,tmp;
		if(o==4){
			printf("%d\n",ask(read()));
			continue;
		}
		l=read(),r=read();
		if(o==1||o==2)work(l,r,read(),o-1);
		else del(l,r);
	}
	return 0;
}
```

这里是点名被卡的 fhq Treap 做法，讲述了较多奇技淫巧和代码实现细节，如果想看到更详细的解析，请前往其他博客处查看。

下文中的 $N=\mathcal{O}(n\log n)$ 指平衡树的节点个数。

首先这道题的四个操作看着就很能用平衡树来解决，有关 fhq Treap 的知识相信大家都会，在此略去。

笔者的代码用时为 $739\text{ms}$，空间为 $299.78\text{MB}$，下面将会讲述如何使用 fhq Treap 解决本题。

首先先写出一颗普通的 fhq Treap，然后在每次修改（即 `split`，`merge` 和 `pushdown`）时都对于当前的版本进行一次备份，然后在备份上进行更改。

这个时候发现前两个操作很难处理，我们不妨定义一种“虚点”，其权值为 $0$ 且不计入子树的大小（即如下代码中的 $siz$）中，也就是说，这棵 fhq Treap 是“半 Leafy 的”。

以下为 `node` 的定义：

```cpp
struct op
{
    int ls, rs, siz, sum;
    bool rel, val, rev;
} p[N];
```

其中 `rel` 为真表示这个点是“实点”，反之则为“虚点”。

发现 `rel`，`val`，`rev` 都是 `bool` 变量，所以可以分别使用一个大小为 $N$ 的 `bitset` 进行存储。

你可能会发现上面的定义没有常见的 `key`，因为在 fhq Treap 中，一种不需要比较键值的方式是用 $\dfrac{siz_x}{siz_x+siz_y}$ 来加权比较 $x$ 和 $y$ 的键值。

如果用了常见的 `key` 的方法的话，除了空间问题（带一个 $\dfrac{5}{4}$ 的常数）外，还有可能会有由于复制操作带来的键值相同问题，而对于集合 $S_1,S_2$，$\max\limits_{x\in S_1}x>\max\limits_{x\in S_2}x$ 的概率为 $\dfrac{|S_1|}{|S_1|+|S_2|}$，证明只需考虑 $S_1\cup S_2$ 的最大值由哪个集合贡献而来即可。

现在直接按照别的题解一般实现无法做到优秀的复杂度，因为 fhq Treap 的虚点不能动态调整（也就是使用如下代码 `Merge` 虚点后再将 $\mathcal{O}(\log k)$ 个“半成品”合并起来复杂度不正确）。

```cpp
int Merge(int x, int y)
{
    int z = ++tot;
    p[z].ls = x, p[z].rs = y;
    rel.reset(z), val.reset(z), rev.reset(z);
    p[z].siz = p[x].siz + p[y].siz;
    p[z].sum = p[x].sum + p[y].sum;
    return z;
}
```

因为这可以通过复制再删除迭代的方式被搞炸，复杂度是错误的。

发现到对于给定的 $k$，我们求出最小的 $k'=2^{x}$，然后将其复制 $k'$ 编后截取前缀，这样只需使用到 $1$ 个半成品。

但这样无法通过 lxl 精心设计的“不含操作 $2$ 的测试点”，一个乱搞的方法是，在每次 $1,2$ 操作后，随机选取一个位置，将序列分为两段，再将它们合并，最后的时间复杂度不会分析，但是能过。

参考代码：

```cpp
#include <bits/stdc++.h>

using namespace std;

inline int read()
{
    int x;
    char c;
    while ((c = getchar()) < '0' || c > '9');
    x = c - '0';
    while ((c = getchar()) >= '0' && c <= '9') {
        x = (x << 3) + (x << 1) + (c ^ '0');
    }
    return x;
}

const int N = 2e7 + 5;

bitset<N> rel, val, rev;

struct op
{
    int ls, rs, siz, sum;
} p[N];

int rt, tot;
mt19937 rnd;

inline int newNode(int x)
{
    p[++tot].ls = 0;
    p[tot].rs = 0;
    p[tot].siz = 1;
    rel.set(tot);
    p[tot].sum = x;
    if (x) {
        val.set(tot);
    }
    return tot;
}

inline int backup(int x)
{
    if (!x) {
        return x;
    }
    p[++tot] = p[x];
    if (rel.test(x)) {
        rel.set(tot);
    }
    if (val.test(x)) {
        val.set(tot);
    }
    if (rev.test(x)) {
        rev.set(tot);
    }
    return tot;
}

inline void pushdown(int x)
{
    if (rev.test(x)) {
        p[x].ls = backup(p[x].ls);
        p[x].rs = backup(p[x].rs);
        rev.flip(p[x].ls);
        rev.flip(p[x].rs);
        swap(p[p[x].ls].ls, p[p[x].ls].rs);
        swap(p[p[x].rs].ls, p[p[x].rs].rs);
        rev.reset(x);
    }
    return;
}

int merge(int x, int y)
{
    if (!x || !y) {
        return x | y;
    }
    if ((int)((unsigned int)rnd() % (p[x].siz + p[y].siz)) < p[x].siz) {
        x = backup(x), pushdown(x);
        p[x].siz += p[y].siz;
        p[x].sum += p[y].sum;
        p[x].rs = merge(p[x].rs, y);
        return x;
    }
    y = backup(y), pushdown(y);
    p[y].siz += p[x].siz;
    p[y].sum += p[x].sum;
    p[y].ls = merge(x, p[y].ls);
    return y;
}

void split(int x, int k, int &a, int &b)
{
    if (!x) {
        a = b = 0;
        return;
    }
    x = backup(x);
    pushdown(x);
    if (p[p[x].ls].siz >= k) {
        b = x;
        split(p[x].ls, k, a, p[b].ls);
    } else {
        a = x;
        split(p[x].rs, k - p[p[x].ls].siz - rel.test(x), p[a].rs, b);
    }
    p[x].siz = p[p[x].ls].siz + p[p[x].rs].siz + rel.test(x);
    p[x].sum = p[p[x].ls].sum + p[p[x].rs].sum + val.test(x);
    return;
}

int Merge(int x, int y)
{
    int z = ++tot;
    p[z].ls = x, p[z].rs = y;
    rel.reset(z), val.reset(z), rev.reset(z);
    p[z].siz = p[x].siz + p[y].siz;
    p[z].sum = p[x].sum + p[y].sum;
    return z;
}

inline int power(int x, int y, int type)
{
    int len = p[x].siz * y, dt = 0, ty = y;
    y = 1;
    while (y < ty) {
        y <<= 1;
    }
    if (type == 1) {
        while (y) {
            if (y & 1) {
                dt = x;
            }
            x = Merge(x, x);
            y >>= 1;
        }
    } else {
        int c = x;
        x = backup(x);
        rev.flip(x);
        swap(p[x].ls, p[x].rs);
        int d = x;
        while (y) {
            if (y & 1) {
                dt = c;
            }
            int C = Merge(c, d), D = Merge(d, c);
            c = C, d = D;
            y >>= 1;
        }
    }
    if (y != ty) {
        int L, R;
        split(dt, len, L, R);
        dt = L;
    }
    return dt;
}

int getKth(int x, int y)
{
    if (val.test(x) && p[p[x].ls].sum + val.test(x) == y) {
        return p[p[x].ls].siz + 1;
    }
    pushdown(x);
    if (p[p[x].ls].sum >= y) {
        return getKth(p[x].ls, y);
    }
    return p[p[x].ls].siz + rel.test(x) + getKth(p[x].rs, y - p[p[x].ls].sum - val.test(x));
}

signed main()
{
    int n = read();
    char c;
    while ((c = getchar()) != '0' && c != '1');
    for (int i = 1; i <= n; ++i) {
        int x = c ^ '0';
        c = getchar();
        rt = merge(rt, newNode(x));
    }
    int m = read();
    while (m--) {
        int opt = read();
        if (opt <= 2) {
            int l = read(), r = read(), k = read(), x, y, z;
            split(rt, r, y, z);
            split(y, l - 1, x, y);
            y = power(y, k, opt);
            rt = merge(merge(x, y), z);
            if (p[rt].siz != 1) {
                int x, y;
                int pos = rnd() % (p[rt].siz - 1) + 1;
                split(rt, pos, x, y);
                rt = merge(x, y);
            }
        } else if (opt == 3) {
            int l = read(), r = read(), x, y, z;
            split(rt, r, y, z);
            split(y, l - 1, x, y);
            rt = merge(x, z);
        } else if (opt == 4) {
            int k = read();
            if (k > p[rt].sum) {
                puts("-1");
                continue;
            }
            printf("%d\n", getKth(rt, k));
        }
    }
    return 0;
}
```

