#include<bits/stdc++.h>
#define For(i,j,k) for(int i=(j);i<=(k);i++)
#define dFor(i,j,k) for(int i=(j);i>=(k);i--)
using namespace std;
#define MAXN 100005
#define MAXM 35
random_device rd;
mt19937 Rand(rd());
int n,m;
char a[MAXN];
struct Node{
    int ls,rs,val,pri;
    int sz,sum;
    bool rev;
}tr[MAXN*512];
int cnt=0;
int New(int x){
    int c=++cnt;
    tr[c].val=tr[c].sum=x;
    tr[c].sz=1;
    tr[c].pri=Rand();
    return c;
}
inline int clone(int c){
    tr[++cnt]=tr[c];
    return cnt;
}
inline void Update(int c){
    tr[c].sz=tr[tr[c].ls].sz+tr[tr[c].rs].sz+1;
    tr[c].sum=tr[tr[c].ls].sum+tr[tr[c].rs].sum+tr[c].val;
}
inline int Rev(int c){
    if(!c) return 0;
    c=clone(c);
    swap(tr[c].ls,tr[c].rs);
    tr[c].rev^=1;
    return c;
}
inline void Down(int c){
    if(tr[c].rev){
        tr[c].ls=Rev(tr[c].ls);
        tr[c].rs=Rev(tr[c].rs);
        tr[c].rev=0;
    }
}
int Merge(int x,int y){
    if(!x) return y;
    if(!y) return x;
    if(tr[x].pri<tr[y].pri){
        Down(x);
        x=clone(x);
        tr[x].rs=Merge(tr[x].rs,y);
        Update(x);
        return x;
    }else{
        Down(y);
        y=clone(y);
        tr[y].ls=Merge(x,tr[y].ls);
        Update(y);
        return y;
    }
}
void Split(int c,int k,int &x,int &y){
    if(!c){
        x=y=0;
        return ;
    }
    Down(c);
    if(k>=tr[tr[c].ls].sz+1){
        x=clone(c);
        Split(tr[x].rs,k-tr[tr[x].ls].sz-1,tr[x].rs,y);
        Update(x);
    }else{
        y=clone(c);
        Split(tr[y].ls,k,x,tr[y].ls);
        Update(y);
    }
}
int rt;
int Build(int l,int r){
    if(l==r) return New(a[l]-'0');
    int mid=(l+r)>>1;
    return Merge(Build(l,mid),Build(mid+1,r));
}
int query(int c,int k){
    if(tr[c].val&&tr[tr[c].ls].sum+tr[c].val==k){
        return tr[tr[c].ls].sz+1;
    }
    Down(c);
    if(tr[tr[c].ls].sum>=k) return query(tr[c].ls,k);
    else return tr[tr[c].ls].sz+1+query(tr[c].rs,k-tr[tr[c].ls].sum-tr[c].val);
}
int main(){
    ios::sync_with_stdio(0);
    cin.tie(0);
    cin>>n;
    For(i,1,n){
        cin>>a[i];
    }
    rt=Build(1,n);
    cin>>m;
    while(m--){
        int op;
        cin>>op;
        if(op==1){
            int l,r,k;
            cin>>l>>r>>k;
            int x,y,z;
            Split(rt,l-1,x,y);
            Split(y,r-l+1,y,z);
            static int p[MAXM];
            p[0]=y;
            int i=0;
            while((1<<(i+1))<=k){
                i++;
                p[i]=Merge(p[i-1],p[i-1]);
            }
            int u=0;
            For(j,0,i){
                if((k>>j)&1){
                    u=Merge(u,p[j]);
                }
            }
            rt=Merge(Merge(x,u),z);
        }else if(op==2){
            int l,r,k;
            cin>>l>>r>>k;
            int x,y,z;
            Split(rt,l-1,x,y);
            Split(y,r-l+1,y,z);
            static int p[MAXM],q[MAXM];
            p[0]=y;q[0]=Rev(y);
            int i=0;
            while((1<<(i+1))<=k){
                i++;
                p[i]=Merge(p[i-1],q[i-1]);
                q[i]=Merge(q[i-1],p[i-1]);
            }
            int u=0;
            bool b=0;
            dFor(j,i,0){
                if((k>>j)&1){
                    int now=b?q[j]:p[j];
                    u=Merge(u,now);
                    b^=1;
                }
            }
            rt=Merge(Merge(x,u),z);
        }else if(op==3){
            int l,r;
            cin>>l>>r;
            int x,y,z;
            Split(rt,l-1,x,y);
            Split(y,r-l+1,y,z);
            rt=Merge(x,z);
        }else{
            int k;
            cin>>k;
            if(tr[rt].sum<k) cout<<-1<<'\n';
            else cout<<query(rt,k)<<'\n';
        }
    }
    return 0;
}
