inline void Down(int c){
    if(!tr[c].rev) return ;
    tr[c].ls=Rev(tr[c].ls);
    tr[c].rs=Rev(tr[c].rs);
    tr[c].rev=0;
}
inline int Join(int x,int y){
    int c=++tot;
    tr[c].ls=x;
    tr[c].rs=y;
    Update(c);
    return c;
