    if(!x) return y;
    if(!y) return x;
    if(tr[x].sz>=delta*tr[y].sz&&tr[y].sz>=delta*tr[x].sz){
        return Join(x,y);
    }
    if(tr[x].sz<=tr[y].sz){
        Down(y);
        int ls=tr[y].ls,rs=tr[y].rs;
